#!/usr/bin/env node
/**
 * Reads coverage/coverage-summary.json (generated by vitest with the
 * json-summary reporter) and injects/updates coverage badges in README.md
 * files for the root and each library.
 *
 * Badge placement uses HTML comment markers so subsequent runs update
 * in-place rather than appending:
 *   <!-- coverage-badge-start -->![Coverage]()<!-- coverage-badge-end -->
 *
 * Usage: node scripts/update-coverage-badges.js
 */
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { resolve, join } from 'path';

const ROOT = resolve(import.meta.dirname, '..');
const SUMMARY_PATH = join(ROOT, 'coverage', 'coverage-summary.json');

if (!existsSync(SUMMARY_PATH)) {
    console.error(
        'Error: coverage/coverage-summary.json not found.\n' +
            'Run `npm run test:coverage` to generate it.'
    );
    process.exit(1);
}

const summary = JSON.parse(readFileSync(SUMMARY_PATH, 'utf-8'));

// --- Badge helpers ---

function getColor(pct) {
    if (pct >= 90) return 'brightgreen';
    if (pct >= 80) return 'green';
    if (pct >= 70) return 'yellowgreen';
    if (pct >= 60) return 'yellow';
    if (pct >= 50) return 'orange';
    return 'red';
}

function makeBadge(pct) {
    const label = `${pct}%25`; // %25 is URL-encoded %
    const color = getColor(pct);
    return `![Coverage](https://img.shields.io/badge/coverage-${label}-${color})`;
}

// --- Per-library coverage aggregation ---

const LIBS = [
    'async',
    'deep',
    'knex-clickhouse',
    'mapper',
    'react-form',
    'scheduler',
    'schema',
    'schema-json'
];

function calcLibCoverage(lib) {
    const prefix = join(ROOT, 'libs', lib, 'src') + '/';
    let covered = 0,
        total = 0;
    for (const [file, data] of Object.entries(summary)) {
        if (file === 'total') continue;
        if (file.startsWith(prefix)) {
            covered += data.statements.covered;
            total += data.statements.total;
        }
    }
    if (total === 0) return null;
    return parseFloat(((covered / total) * 100).toFixed(1));
}

// --- README badge injection ---

const BADGE_START = '<!-- coverage-badge-start -->';
const BADGE_END = '<!-- coverage-badge-end -->';

function updateReadme(readmePath, badge) {
    if (!existsSync(readmePath)) {
        console.log(`  skipped (not found): ${readmePath}`);
        return;
    }

    let content = readFileSync(readmePath, 'utf-8');

    // Subsequent runs: replace between existing markers
    if (content.includes(BADGE_START)) {
        const escaped = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const regex = new RegExp(
            `${escaped(BADGE_START)}[\\s\\S]*?${escaped(BADGE_END)}`
        );
        content = content.replace(regex, `${BADGE_START}${badge}${BADGE_END}`);
        writeFileSync(readmePath, content);
        console.log(`  updated: ${readmePath}`);
        return;
    }

    // First run: insert after the last consecutive [![ / ![ badge line
    // found within the first 20 lines of the file.
    const lines = content.split('\n');
    let lastBadgeLine = -1;
    for (let i = 0; i < Math.min(lines.length, 20); i++) {
        const trimmed = lines[i].trimStart();
        if (trimmed.startsWith('[![') || trimmed.startsWith('![')) {
            lastBadgeLine = i;
        } else if (lastBadgeLine >= 0) {
            break; // badge block ended
        }
    }

    const insertAt = lastBadgeLine >= 0 ? lastBadgeLine + 1 : 1;
    lines.splice(insertAt, 0, `${BADGE_START}${badge}${BADGE_END}`);
    writeFileSync(readmePath, lines.join('\n'));
    console.log(`  inserted: ${readmePath}`);
}

// --- Main ---

const totalPct = parseFloat(summary.total.statements.pct.toFixed(1));
console.log(`\nOverall statement coverage: ${totalPct}%`);
updateReadme(join(ROOT, 'README.md'), makeBadge(totalPct));

for (const lib of LIBS) {
    const pct = calcLibCoverage(lib);
    if (pct === null) {
        console.log(`  [${lib}] no data — skipped`);
        continue;
    }
    console.log(`  [${lib}] ${pct}%`);
    updateReadme(join(ROOT, 'libs', lib, 'README.md'), makeBadge(pct));
}

console.log('\nDone.\n');
